import { api } from './api';

export interface CreateTemplateDTO {
  lesson_id?: string | null;
  template_type: string;
  difficulty?: string;
  body_template_en: string;
  body_template_vi: string;
  explanation_template_en?: string;
  explanation_template_vi?: string;
  is_premium?: boolean;
  logic_config?: unknown;
  accepted_formulas?: string[];
  tags?: string[];
}

export interface PaginationMeta {
  page: number;
  pageSize: number;
  total: number;
  totalPages: number;
  hasMore: boolean;
}

export interface PaginatedResponse<T> {
  items: T[];
  pagination: PaginationMeta;
}

export interface TemplateFilterMetadata {
  templateTypes: string[];
  grades: Array<{
    id: string;
    slug: string;
    title_en: string;
    title_vi: string;
  }>;
  lessons: Array<{
    id: string;
    title_en: string;
    title_vi: string;
    grade_id: string;
  }>;
  difficulties: string[];
}

export interface GradeTestEligibility {
  eligible: boolean;
  requiredLessonCount: number;
  completedLessonCount: number;
  minimumScore: number;
}

export interface GradeTestAttemptSummary {
  id: string;
  total_score: number | null;
  is_completed: boolean | null;
  started_at: string;
  completed_at?: string | null;
  questionCount: number;
}

export interface GradeTestLessonSummary {
  id: string;
  slug: string;
  title_en: string;
  title_vi: string;
}

export interface GradeTestGradeSummary {
  id: number;
  slug: string;
  title_en: string;
  title_vi: string;
  lessons?: GradeTestLessonSummary[];
}

export interface GradeTest {
  id: string;
  grade_id: number;
  grade_slug: string;
  title_en: string;
  title_vi: string;
  description_en: string;
  description_vi: string;
  questionCount: number;
  availableTemplateCount: number;
  lessonCount: number;
  difficulty: "Beginner" | "Intermediate" | "Advanced";
  iconType: "timer" | "medal" | "target";
  attempts?: GradeTestAttemptSummary[];
  eligibility: GradeTestEligibility;
  grade?: GradeTestGradeSummary;
}

export const testService = {
  createTemplate: async (data: CreateTemplateDTO) => {
    const response = await api.post('/tests/templates', data);
    return response.data;
  },
  createTemplates: async (templates: CreateTemplateDTO[]) => {
    const response = await api.post('/tests/templates', { templates });
    return response.data;
  },
  listTemplates: async (params?: {
    page?: number;
    pageSize?: number;
    search?: string;
    templateType?: string;
    gradeId?: string;
    lessonId?: string;
    difficulty?: string;
    tag?: string;
  }): Promise<PaginatedResponse<any>> => {
    const response = await api.get('/tests/templates', { params });
    return response.data;
  },
  getTemplateFilters: async (): Promise<TemplateFilterMetadata> => {
    const response = await api.get('/tests/templates/filters');
    return response.data;
  },
  getTemplate: async (id: string) => {
    const response = await api.get(`/tests/templates/${id}`);
    return response.data;
  },
  updateTemplate: async (id: string, data: CreateTemplateDTO) => {
    const response = await api.put(`/tests/templates/${id}`, data);
    return response.data;
  },
  removeTemplate: async (id: string) => {
    const response = await api.delete(`/tests/templates/${id}`);
    return response.data;
  },

  getAttempt: async (attemptId: string) => {
    const response = await api.get(`/tests/attempts/${attemptId}`);
    return response.data;
  },
  submitAnswer: async (snapshotId: string, studentAnswer: string) => {
    const response = await api.post('/tests/submit-answer', { snapshotId, studentAnswer });
    return response.data;
  },
  reportQuestion: async (snapshotId: string, reason: string) => {
    const response = await api.post('/tests/question-reports', { snapshotId, reason });
    return response.data;
  },
  listQuestionReports: async (status = "all") => {
    const response = await api.get('/tests/question-reports', { params: { status } });
    return response.data;
  },
  updateQuestionReport: async (id: string, status: string) => {
    const response = await api.patch(`/tests/question-reports/${id}`, { status });
    return response.data;
  },
  listGradeTests: async (): Promise<GradeTest[]> => {
    const response = await api.get('/tests/grade-tests');
    return response.data;
  },
  startGradeTest: async (gradeId: number): Promise<{ id: string }> => {
    const response = await api.post(`/tests/grade-tests/${gradeId}/start`);
    return response.data;
  },
  finishAttempt: async (attemptId: string) => {
    const response = await api.post(`/tests/attempts/${attemptId}/finish`);
    return response.data;
  },

  getPracticeHistory: async () => {
    const response = await api.get('/tests/my-practice-history');
    return response.data;
  },

  exportGradeTestQuestions: async (gradeId: number): Promise<any[]> => {
    const response = await api.get(`/tests/grade-tests/${gradeId}/export-questions`);
    return response.data;
  }
};
